convertToWIASleep.swift:
func convertToWIASleep(samples: [HKCategorySample], hrvSamples: [HKQuantitySample]?) -> SleepRecord {
    // Calculate total duration by stage
    var stageDurations: [Int: TimeInterval] = [:]
    for sample in samples {
        let duration = sample.endDate.timeIntervalSince(sample.startDate)
        stageDurations[sample.value, default: 0] += duration
    }

    let totalSleep = (stageDurations[1] ?? 0) + (stageDurations[3] ?? 0) + (stageDurations[4] ?? 0) + (stageDurations[5] ?? 0)
    let timeInBed = (stageDurations[0] ?? 0) + totalSleep + (stageDurations[2] ?? 0)

    return SleepRecord(
        sleepArchitecture: SleepArchitecture(
            summary: SleepArchitectureSummary(
                totalSleepTime_min: totalSleep / 60,
                sleepEfficiency_pct: (totalSleep / timeInBed) * 100,
                ...
            )
        )
    )
}
